#include <bits/stdc++.h>
using namespace std;
#define int long long
int mod = 19491001;
int n;
char s[1000010];
int len; 
int N; 
int k;
int tot;
int quick_pow (int x, int k) {
    int res = 1;
    while (k) {
        if (k & 1) {
        	res = res * x % mod;
		}
        x = x * x % mod;
        k >>= 1;
    }
    return res;
}
int inv(int x) {
    return quick_pow (x, mod - 2);
}
signed main () {
	char ch = getchar ();
    while (isdigit (ch)) {
    	s[++len] = ch;
    	N = (10 * N + ch - '0') % mod;
    	ch = getchar ();
	}
    cin >> k;
    int i, val;
    for (i = 1; i <= k; i++) {
    	cin >> val;
    	tot = (tot + val) % mod;
    }
    int invk = inv(k);
	cout << (N * k % mod + 2 * N - 2) % mod * tot % mod * invk % mod * invk % mod;
    return 0;
}
